using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private OrderService _sut = null!;

    [TestInitialize]
    public void SetUp()
    {
        _sut = new OrderService();
    }

    // ───────────────────────────────────────────────
    //  CreateOrder – Happy Path
    // ───────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectProperties()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 9.99m, Quantity = 2 }
        };

        // Act
        var before = DateTime.UtcNow;
        var order = _sut.CreateOrder("cust-1", items);
        var after = DateTime.UtcNow;

        // Assert
        Assert.IsNotNull(order);
        Assert.IsFalse(string.IsNullOrWhiteSpace(order.Id));
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(1, order.Items.Count);
        Assert.AreEqual(19.98m, order.Total);
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            "CreatedAt should be between the before and after timestamps.");
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_TotalIsSumOfPriceTimesQuantity()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Alpha", Price = 10.00m, Quantity = 1 },
            new() { ProductName = "Beta",  Price = 5.50m,  Quantity = 3 },
            new() { ProductName = "Gamma", Price = 2.25m,  Quantity = 4 }
        };

        // Act
        var order = _sut.CreateOrder("cust-2", items);

        // Assert — 10 + 16.50 + 9 = 35.50
        Assert.AreEqual(35.50m, order.Total);
        Assert.AreEqual(3, order.Items.Count);
    }

    [TestMethod]
    [DataRow(1.00, 1, 1.00,  DisplayName = "1 × $1.00 = $1.00")]
    [DataRow(7.50, 2, 15.00, DisplayName = "2 × $7.50 = $15.00")]
    [DataRow(0.99, 10, 9.90, DisplayName = "10 × $0.99 = $9.90")]
    [DataRow(100.00, 5, 500.00, DisplayName = "5 × $100.00 = $500.00")]
    public void CreateOrder_VariousPriceQuantityCombos_CalculatesTotalCorrectly(
        double price, int quantity, double expectedTotal)
    {
        // Arrange — DataRow doesn't support decimal, so cast from double
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = (decimal)price, Quantity = quantity }
        };

        // Act
        var order = _sut.CreateOrder("cust-param", items);

        // Assert
        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }

    [TestMethod]
    public void CreateOrder_ValidOrder_IsRetrievableViaGetOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Stored", Price = 4.00m, Quantity = 1 }
        };

        // Act
        var created = _sut.CreateOrder("cust-store", items);
        var retrieved = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(retrieved);
        Assert.AreSame(created, retrieved);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_AssignsDifferentIds()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Any", Price = 1.00m, Quantity = 1 }
        };

        // Act
        var order1 = _sut.CreateOrder("cust-a", items);
        var order2 = _sut.CreateOrder("cust-a", items);

        // Assert
        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    // ───────────────────────────────────────────────
    //  CreateOrder – Error Cases
    // ───────────────────────────────────────────────

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "X", Price = 1m, Quantity = 1 }
        };

        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder(null!, items));
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        Assert.ThrowsExactly<ArgumentNullException>(
            () => _sut.CreateOrder("cust-1", null!));
    }

    [TestMethod]
    public void CreateOrder_EmptyItemsList_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));

        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // ───────────────────────────────────────────────
    //  GetOrder
    // ───────────────────────────────────────────────

    [TestMethod]
    public void GetOrder_ExistingOrderId_ReturnsCorrectOrder()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Found", Price = 3.00m, Quantity = 1 }
        };
        var created = _sut.CreateOrder("cust-get", items);

        // Act
        var result = _sut.GetOrder(created.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(created.Id, result.Id);
        Assert.AreEqual("cust-get", result.CustomerId);
    }

    [TestMethod]
    public void GetOrder_NonExistentOrderId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GetOrder_MultipleOrdersExist_ReturnsCorrectOne()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = 1.00m, Quantity = 1 }
        };

        var order1 = _sut.CreateOrder("cust-a", items);
        var order2 = _sut.CreateOrder("cust-b", items);
        var order3 = _sut.CreateOrder("cust-c", items);

        // Act
        var result = _sut.GetOrder(order2.Id);

        // Assert
        Assert.IsNotNull(result);
        Assert.AreSame(order2, result);
    }

    // ───────────────────────────────────────────────
    //  GetOrdersByCustomer
    // ───────────────────────────────────────────────

    [TestMethod]
    public void GetOrdersByCustomer_CustomerHasOrders_ReturnsAllMatchingOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = 5.00m, Quantity = 1 }
        };

        var o1 = _sut.CreateOrder("cust-multi", items);
        var o2 = _sut.CreateOrder("cust-multi", items);
        _sut.CreateOrder("cust-other", items); // different customer

        // Act
        var results = _sut.GetOrdersByCustomer("cust-multi");

        // Assert
        Assert.AreEqual(2, results.Count);
        Assert.IsTrue(results.Any(o => o.Id == o1.Id));
        Assert.IsTrue(results.Any(o => o.Id == o2.Id));
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrdersForCustomer_ReturnsEmptyList()
    {
        // Arrange — create an order for a different customer
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = 1.00m, Quantity = 1 }
        };
        _sut.CreateOrder("cust-other", items);

        // Act
        var results = _sut.GetOrdersByCustomer("cust-none");

        // Assert
        Assert.IsNotNull(results);
        Assert.AreEqual(0, results.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleCustomers_ReturnsOnlyRequestedCustomerOrders()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Item", Price = 2.00m, Quantity = 1 }
        };

        _sut.CreateOrder("alice", items);
        _sut.CreateOrder("alice", items);
        _sut.CreateOrder("bob", items);
        _sut.CreateOrder("charlie", items);
        _sut.CreateOrder("charlie", items);
        _sut.CreateOrder("charlie", items);

        // Act
        var aliceOrders = _sut.GetOrdersByCustomer("alice");
        var bobOrders = _sut.GetOrdersByCustomer("bob");
        var charlieOrders = _sut.GetOrdersByCustomer("charlie");

        // Assert
        Assert.AreEqual(2, aliceOrders.Count);
        Assert.AreEqual(1, bobOrders.Count);
        Assert.AreEqual(3, charlieOrders.Count);

        Assert.IsTrue(aliceOrders.All(o => o.CustomerId == "alice"));
        Assert.IsTrue(bobOrders.All(o => o.CustomerId == "bob"));
        Assert.IsTrue(charlieOrders.All(o => o.CustomerId == "charlie"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_EmptyService_ReturnsEmptyList()
    {
        var results = _sut.GetOrdersByCustomer("anyone");

        Assert.IsNotNull(results);
        Assert.AreEqual(0, results.Count);
    }
}

